import './App.css';
import { BrowserRouter as Router, Switch, Route,  } from "react-router-dom";
import Home from "./pages/index";

function App() {
  return (
    <Router>
    <Switch>
         <Route path="/"><App /></Route>
         <Route path="*"><Whoops404/></Route>
     </Switch>
  </Router>
  );
}

export default App;
